import{_ as e,c as t,a1 as r,o as n}from"./chunks/framework.Bff2UY46.js";const a="/rby1-dev/assets/mermaid-robot-command.CD5Ugd5j.png",s="/rby1-dev/assets/mermaid-wholebody-command.ByorYerK.png",i="/rby1-dev/assets/mermaid-body-command.B6J5MRwD.png",l="/rby1-dev/assets/mermaid-torso-command.BgpYMM-Q.png",m="/rby1-dev/assets/mermaid-left-command.qoharI8A.png",d="/rby1-dev/assets/mermaid-right-command.BCRoJ5ne.png",C=JSON.parse('{"title":"Coming Soon","description":"","frontmatter":{"title":"Coming Soon","outline":"deep"},"headers":[],"relativePath":"docs/development/rby1-sdk/controllers.md","filePath":"docs/development/rby1-sdk/controllers.md"}'),c={name:"docs/development/rby1-sdk/controllers.md"};function h(g,o,u,p,y,f){return n(),t("div",null,o[0]||(o[0]=[r('<h1 id="controllers" tabindex="-1">Controllers <a class="header-anchor" href="#controllers" aria-label="Permalink to &quot;Controllers&quot;">​</a></h1><h2 id="robot-command-hierarchy" tabindex="-1">Robot Command Hierarchy <a class="header-anchor" href="#robot-command-hierarchy" aria-label="Permalink to &quot;Robot Command Hierarchy&quot;">​</a></h2><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>The robot commands are divided into three main types:</p><ol><li><strong>WholeBodyCommand</strong>: Controls the entire robot with 24 degrees of freedom (DOF) in a single command.</li><li><strong>BodyCommand</strong>: Controls the body of the robot with 20 DOF, either using the entire body at once or split into components.</li><li><strong>JogCommand</strong>: Controls smaller, individual movements, typically used for fine adjustments.</li></ol><figure><img src="'+a+'" alt="missing" style="margin:auto;"></figure><h3 id="wholebodycommand" tabindex="-1">WholeBodyCommand <a class="header-anchor" href="#wholebodycommand" aria-label="Permalink to &quot;WholeBodyCommand&quot;">​</a></h3><p>This command controls all the major components of the robot, including arms, torso, and legs. It supports various controllers for managing the full body of the robot. The primary use case is for synchronized movements where multiple parts of the robot are involved.</p><figure><img src="'+s+'" alt="missing" style="margin:auto;"></figure><h4 id="controllers-under-wholebodycommand" tabindex="-1">Controllers under WholeBodyCommand: <a class="header-anchor" href="#controllers-under-wholebodycommand" aria-label="Permalink to &quot;Controllers under WholeBodyCommand:&quot;">​</a></h4><ul><li><strong>JointPositionController</strong>: Manages the position of each joint.</li><li><strong>CartesianController</strong>: Controls the Cartesian position of the robot.</li><li><strong>ImpedanceController</strong>: Allows control of force and motion, useful for interactions with the environment.</li><li><strong>GravityCompensationController</strong>: Compensates for gravitational forces, making the robot more energy-efficient during holding positions.</li></ul><p>This command sends a <strong>24 DOF</strong> control signal all at once.</p><h3 id="bodycommand" tabindex="-1">BodyCommand <a class="header-anchor" href="#bodycommand" aria-label="Permalink to &quot;BodyCommand&quot;">​</a></h3><p>The BodyCommand focuses on the robot&#39;s torso, arms, and other components that make up the core of the robot. It typically handles <strong>20 DOF</strong>. You can use multiple controllers here to control specific parts of the body.</p><figure><img src="'+i+'" alt="missing" style="margin:auto;"></figure><h4 id="two-ways-to-use-bodycommand" tabindex="-1">Two Ways to Use BodyCommand: <a class="header-anchor" href="#two-ways-to-use-bodycommand" aria-label="Permalink to &quot;Two Ways to Use BodyCommand:&quot;">​</a></h4><ol><li><strong>All components at once</strong>: Controls all 20 DOF with a single command.</li><li><strong>Split into Body Components</strong>: Breaks the control into smaller parts, each controlling individual components like arms or torso.</li></ol><figure><img src="'+l+'" alt="missing" style="margin:auto;"></figure><figure><img src="'+m+'" alt="missing" style="margin:auto;"></figure><figure><img src="'+d+'" alt="missing" style="margin:auto;"></figure>',20)]))}const v=e(c,[["render",h]]);export{C as __pageData,v as default};
